// ًں†• v6.41.94: Bild â†’ Text-Beschreibung fأ¼r die Claude-Bridge.
// Nimmt ein Foto vom Claude-Bot, schickt's an Claude Vision, gibt eine Beschreibung
// im Plain-Text zurأ¼ck (gesamter sichtbarer Text + UI-Elemente + Buttons + Fehlermeldungen).
// Damit ich (Claude in der Terminal-Session) ohne lokalen Bilddownload sehen kann was auf
// dem Screenshot drauf ist.
async function describeImageForClaudeBridge(botTokenForFile, fileId, caption = '') {
    try {
        const anthropicKey = await getAnthropicApiKey();
        if (!anthropicKey) return 'âڑ ï¸ڈ Kein Anthropic API Key konfiguriert â€” Bild kann nicht analysiert werden.';
        // Datei-Pfad bei Telegram holen
        const fileResp = await fetch(`https://api.telegram.org/bot${botTokenForFile}/getFile`, {
            method: 'POST', headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ file_id: fileId })
        });
        const fileData = await fileResp.json();
        if (!fileData.ok || !fileData.result?.file_path) return 'âڑ ï¸ڈ Bild-Datei konnte nicht abgerufen werden.';
        const fileUrl = `https://api.telegram.org/file/bot${botTokenForFile}/${fileData.result.file_path}`;
        const imgResp = await fetch(fileUrl);
        if (!imgResp.ok) return 'âڑ ï¸ڈ Bild-Download fehlgeschlagen.';
        const base64 = Buffer.from(await imgResp.arrayBuffer()).toString('base64');
        const fp = fileData.result.file_path || '';
        const mediaType = fp.endsWith('.png') ? 'image/png' : fp.endsWith('.webp') ? 'image/webp' : 'image/jpeg';

        const prompt = `Beschreibe dieses Bild fأ¼r einen Entwickler-Assistenten der den Code des Taxi-Apps weiterentwickelt.
${caption ? `Zusatz-Text vom Sender: "${caption}"\n` : ''}
Lies ALLEN sichtbaren Text wortgenau. Beschreibe:
- Was fأ¼r ein Bildschirm/App das ist (Firebase Console, Telegram, Browser, Fahrer-App, etc.)
- Welcher Bereich/Tab/Menأ¼
- Sichtbare Buttons (mit Text)
- Fehlermeldungen, Stack-Traces, Code-Zeilen WORTGENAU
- Tabellen-Inhalte zeilenweise
- Status-Anzeigen, Zأ¤hler, Warnungen
- Visuelle Auffأ¤lligkeiten

Antworte als reine Beschreibung in Deutsch, knapp aber vollstأ¤ndig. Maximal 1500 Zeichen.`;

        const visionResp = await callAnthropicAPI(anthropicKey, 'claude-haiku-4-5-20251001', 1500, [{
            role: 'user',
            content: [
                { type: 'image', source: { type: 'base64', media_type: mediaType, data: base64 } },
                { type: 'text', text: prompt }
            ]
        }]);
        const text = (visionResp.content?.[0]?.text || '').trim();
        return text || 'âڑ ï¸ڈ Vision-API gab keine Beschreibung zurأ¼ck.';
    } catch (e) {
        console.error('describeImageForClaudeBridge:', e.message);
        return `âڑ ï¸ڈ Fehler bei Bildanalyse: ${e.message}`;
    }
}

// ًں†• v6.41.92: Wiederverwendbare Whisper-Transkription fأ¼r beide Bots.
// Nimmt einen Bot-Token + file_id, lأ¤dt die Audio-Datei via Telegram-File-API,
// schickt sie an OpenAI Whisper, gibt Transkript-Text zurأ¼ck (oder null bei Fehler).
async function transcribeAudio(botTokenForFile, fileId, contextHint = '') {
    try {
        const openaiKey = await getOpenAiApiKey();
        if (!openaiKey) { console.error('transcribeAudio: kein OpenAI API Key'); return null; }
        // Datei-Pfad bei Telegram holen
        const fileResp = await fetch(`https://api.telegram.org/bot${botTokenForFile}/getFile`, {
            method: 'POST', headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ file_id: fileId })
        });
        const fileData = await fileResp.json();
        if (!fileData.ok || !fileData.result?.file_path) return null;
        const fileUrl = `https://api.telegram.org/file/bot${botTokenForFile}/${fileData.result.file_path}`;
        const audioResp = await fetch(fileUrl);
        if (!audioResp.ok) return null;
        const audioBuffer = Buffer.from(await audioResp.arrayBuffer());
        // Whisper Multipart-Body bauen
        const boundary = '----WhisperBoundary' + Date.now();
        const formParts = [];
        formParts.push(`--${boundary}\r\nContent-Disposition: form-data; name="model"\r\n\r\nwhisper-1`);
        formParts.push(`--${boundary}\r\nContent-Disposition: form-data; name="language"\r\n\r\nde`);
        if (contextHint) {
            formParts.push(`--${boundary}\r\nContent-Disposition: form-data; name="prompt"\r\n\r\n${contextHint}`);
        }
        const fileHeader = `--${boundary}\r\nContent-Disposition: form-data; name="file"; filename="voice.ogg"\r\nContent-Type: audio/ogg\r\n\r\n`;
        const fileFooter = `\r\n--${boundary}--\r\n`;
        const textParts = formParts.join('\r\n') + '\r\n';
        const textBefore = Buffer.from(textParts + fileHeader);
        const textAfter = Buffer.from(fileFooter);
        const bodyBuffer = Buffer.concat([textBefore, audioBuffer, textAfter]);
        const transcribeResp = await fetch('https://api.openai.com/v1/audio/transcriptions', {
            method: 'POST',
            headers: { 'Authorization': `Bearer ${openaiKey}`, 'Content-Type': `multipart/form-data; boundary=${boundary}` },
            body: bodyBuffer
        });
        if (!transcribeResp.ok) {
            const errData = await transcribeResp.json().catch(() => ({}));
            console.error('transcribeAudio Whisper-Fehler:', errData.error?.message || transcribeResp.status);
            return null;
        }
        const transcribeResult = await transcribeResp.json();
        return (transcribeResult.text || '').trim() || null;
    } catch (e) {
        console.error('transcribeAudio Exception:', e.message);
        return null;
    }
}

async function sendClaudeBotMessage(chatId, text, extraParams = {}) {
    const token = await loadClaudeBotToken();
    if (!token) { console.error('Kein Claude-Bot-Token!'); return null; }
    try {
        const resp = await fetch(`https://api.telegram.org/bot${token}/sendMessage`, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ chat_id: chatId, text, parse_mode: 'HTML', ...extraParams })
        });
        const data = await resp.json();
        if (!data.ok) console.error('Claude-Bot sendMessage Fehler:', data.description);
        return data.ok ? data.result : null;
    } catch (e) {
        console.error('Claude-Bot sendMessage Exception:', e.message);
        return null;
    }
}

// ًں†• v6.62.143: Cloud-TTS fuer Bridge-Nachrichten (Patrick: 'kannst du mir hier auf
// dem Handy eine Funktion bauen die mir die Sachen vorliest?'). Bei langen
// Bridge-Pushes generiert Google Cloud TTS aus dem Text eine Voice-Message und
// schickt sie zusaetzlich via sendVoice an den gleichen Bot/Chat.
async function generateTtsAudio(text) {
    try {
        const apiKey = (await db.ref('settings/googlePlacesApiKey').once('value')).val();
        if (!apiKey) { console.warn('TTS: kein Google API Key'); return null; }
        const voiceName = (await db.ref('settings/bridge/voiceName').once('value')).val()
                          || 'de-DE-Wavenet-F';
        const speakRate = (await db.ref('settings/bridge/speakingRate').once('value')).val() || 1.0;
        // Text fuer TTS bereinigen â€” Emoji/Markdown raus, sonst spricht die Stimme 'ًںڑ•' aus
        const _spoken = String(text)
            .replace(/[\p{Emoji_Presentation}\p{Extended_Pictographic}]/gu, '')
            .replace(/[*_`#~]+/g, '')
            .replace(/\n+/g, '. ')
            .replace(/\s+/g, ' ')
            .trim()
            .slice(0, 4500);
        if (!_spoken) return null;
        const resp = await fetch(
            `https://texttospeech.googleapis.com/v1/text:synthesize?key=${apiKey}`,
            {
                method: 'POST',
                headers: { 'Content-Type': 'application/json' },
                body: JSON.stringify({
                    input: { text: _spoken },
                    voice: { languageCode: 'de-DE', name: voiceName },
                    audioConfig: { audioEncoding: 'OGG_OPUS', speakingRate: speakRate }
                })
            }
        );
        const data = await resp.json();
        if (!data.audioContent) {
            console.error('TTS-API-Fehler:', data.error?.message || data);
            return null;
        }
        return Buffer.from(data.audioContent, 'base64');
    } catch (e) {
        console.error('generateTtsAudio Exception:', e.message);
        return null;
    }
}

async function sendTelegramVoice(token, chatId, audioBuffer, replyToMessageId) {
    try {
        const fd = new FormData();
        fd.append('chat_id', String(chatId));
        fd.append('voice', new Blob([audioBuffer], { type: 'audio/ogg' }), 'voice.ogg');
        if (replyToMessageId) fd.append('reply_to_message_id', String(replyToMessageId));
        const resp = await fetch(`https://api.telegram.org/bot${token}/sendVoice`, {
            method: 'POST',
            body: fd
        });
        const data = await resp.json();
        if (!data.ok) console.error('sendVoice Fehler:', data.description);
        return data.ok ? data.result : null;
    } catch (e) {
        console.error('sendVoice Exception:', e.message);
        return null;
    }
}

async function maybeSendVoiceVersion(text, chatId, useClaudeBot, replyToMessageId) {
    try {
        const enabled = (await db.ref('settings/bridge/voiceMode').once('value')).val();
        if (enabled === false) return; // explizit abgeschaltet
        const minChars = (await db.ref('settings/bridge/voiceMinChars').once('value')).val() || 200;
        if (!text || text.length < minChars) return;
        const audio = await generateTtsAudio(text);
        if (!audio) return;
        const token = useClaudeBot ? await loadClaudeBotToken() : await loadBotToken();
        if (!token) return;
        await sendTelegramVoice(token, chatId, audio, replyToMessageId);
    } catch (e) {
        console.error('maybeSendVoiceVersion Fehler:', e.message);
    }
}

async function ensureWebhookSecret() {
    const snap = await db.ref('settings/telegram/webhookSecret').once('value');
    if (snap.val()) return snap.val();
    // Kein Secret vorhanden â†’ automatisch generieren und speichern
    const { randomBytes } = await import('crypto');
    const secret = randomBytes(32).toString('hex');
    await db.ref('settings/telegram/webhookSecret').set(secret);
    return secret;
}

async function sendTelegramMessage(chatId, text, extraParams = {}) {
    const token = await loadBotToken();
    if (!token) { console.error('Kein Bot-Token!'); return null; }
    try {
        // ًں†• v6.38.55: Bot-Antwort im Log speichern (gekأ¼rzt auf 120 Zeichen)
        // ًں”§ v6.38.58: Button-TEXTE im Log anzeigen (nicht nur Anzahl)
        const _cleanText = (text || '').replace(/<[^>]+>/g, '').replace(/\n+/g, ' ').trim();
        const _shortText = _cleanText.length > 120 ? _cleanText.substring(0, 117) + '...' : _cleanText;
        let _btnInfo = '';
        if (extraParams.reply_markup?.inline_keyboard) {
            const _allBtns = extraParams.reply_markup.inline_keyboard.flat();
            if (_allBtns.length > 0) {
                const _btnTexts = _allBtns.map(b => b.text).join(' | ');
                _btnInfo = ` [${_btnTexts}]`;
            }
        }
        addTelegramLog('ًں¤–', chatId, `Bot: ${_shortText}${_btnInfo}`).catch(() => {});

        const resp = await fetch(`https://api.telegram.org/bot${token}/sendMessage`, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ chat_id: chatId, text, parse_mode: 'HTML', ...extraParams })
        });
        const data = await resp.json();
        if (!data.ok) console.error('sendMessage Fehler:', data.description);
        return data.ok ? data.result : null;
    } catch (e) {
        console.error('sendMessage Exception:', e.message);
        return null;
    }
}

// ًں”§ v6.38.49: Fehler-Nachricht mit Menأ¼-Buttons â€” KEINE SACKGASSEN!
// Wird bei JEDEM Fehler aufgerufen, damit der Kunde immer weiterkommt
async function sendErrorWithMenu(chatId, errorText, options = {}) {
    const _menuButtons = [
        [{ text: 'ًںڑ• Neue Fahrt buchen', callback_data: 'menu_buchen' }],
        [{ text: 'ًںڈ  Hauptmenأ¼', callback_data: 'main_menu' }]
    ];
    if (options.retryCallback) {
        _menuButtons.unshift([{ text: 'ًں”„ Nochmal versuchen', callback_data: options.retryCallback }]);
    }
    if (options.extraButtons) {
        _menuButtons.unshift(...options.extraButtons);
    }
    const _msg = `${errorText}\n\nًں’، <b>Was mأ¶chten Sie tun?</b>`;
    await sendTelegramMessage(chatId, _msg, { reply_markup: { inline_keyboard: _menuButtons } });
    // Pending lأ¶schen damit der Kunde sauber neu starten kann
    if (options.clearPending !== false) {
        try { await deletePending(chatId); } catch(_e) {}
    }
}

