// ًں†• v6.38.44: ZENTRALES FEHLERANALYSE-SYSTEM
// Alle Fehler werden in Firebase gespeichert + Admin wird alarmiert
// â•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گ

// Schweregrade: 'critical' (Admin-Alert sofort), 'error' (geloggt + tأ¤glicher Bericht), 'warning' (nur geloggt)
const _errorRateLimit = {}; // Schutz gegen Endlos-Loops: max 1 Alert pro Funktion pro 5 Min

async function logError(functionName, error, context = {}) {
    const now = Date.now();
    const severity = context.severity || 'error';
    const dayKey = getTodayLogKey();

    const entry = {
        t: now,
        ts: new Date(now).toLocaleString('de-DE', { timeZone: 'Europe/Berlin' }),
        fn: functionName,
        severity,
        msg: error?.message || String(error),
        stack: (error?.stack || '').substring(0, 1000),
        chatId: context.chatId ? String(context.chatId) : null,
        rideId: context.rideId || null,
        data: context.data ? JSON.stringify(context.data).substring(0, 500) : null,
        pendingState: context.pendingState ? JSON.stringify(context.pendingState).substring(0, 300) : null,
        version: CLOUD_FUNCTIONS_VERSION
    };

    // 1. In Firebase speichern: /errorLogs/{datum}/{id}
    try {
        await db.ref(`errorLogs/${dayKey}`).push(entry);
    } catch (e2) {
        console.error('â‌Œ logError: Firebase-Write fehlgeschlagen:', e2.message);
    }

    // 2. Console-Log (fأ¼r Cloud Logging / GCP)
    const logPrefix = severity === 'critical' ? 'ًں”´ CRITICAL' : (severity === 'warning' ? 'âڑ ï¸ڈ WARNING' : 'â‌Œ ERROR');
    console.error(`${logPrefix} [${functionName}] ${entry.msg}`, entry.stack ? `\n${entry.stack}` : '');

    // 3. Admin-Alert bei kritischen Fehlern (Rate-Limited: max 1 pro 5 Min pro Funktion)
    if (severity === 'critical') {
        const rateKey = `${functionName}_${Math.floor(now / 300000)}`; // 5-Min-Fenster
        if (!_errorRateLimit[rateKey]) {
            _errorRateLimit[rateKey] = true;
            try {
                const alertMsg = `ًں”´ <b>KRITISCHER FEHLER!</b>\n\n` +
                    `âڑ™ï¸ڈ <b>Funktion:</b> ${functionName}\n` +
                    `â‌Œ <b>Fehler:</b> ${entry.msg}\n` +
                    (context.chatId ? `ًں’¬ <b>Chat:</b> ${context.chatId}\n` : '') +
                    (context.rideId ? `ًںڑ• <b>Fahrt:</b> ${context.rideId}\n` : '') +
                    `ًں•گ <b>Zeit:</b> ${entry.ts}\n` +
                    `ًں“¦ <b>Version:</b> v${CLOUD_FUNCTIONS_VERSION}\n\n` +
                    (entry.stack ? `<pre>${entry.stack.substring(0, 300)}</pre>\n\n` : '') +
                    `ًں’، <i>Fehlerlog: Firebase â†’ errorLogs/${dayKey}</i>`;
                await sendToAllAdmins(alertMsg);
            } catch (e3) {
                console.error('â‌Œ logError: Admin-Alert fehlgeschlagen:', e3.message);
            }
        }
    }

    // 4. Lifecycle-Log wenn Ride vorhanden
    if (context.rideId) {
        await addRideLog(context.rideId, 'â‌Œ', `Fehler in ${functionName}: ${entry.msg}`);
    }

    // Cleanup: alte Rate-Limit-Keys entfernen (أ¤lter als 10 Min)
    for (const key of Object.keys(_errorRateLimit)) {
        const keyTime = parseInt(key.split('_').pop()) * 300000;
        if (now - keyTime > 600000) delete _errorRateLimit[key];
    }
}

// ًں†• v6.38.44: Daten-Inkonsistenz melden (Strecke fehlt, Preis fehlt, etc.)
// ًں”§ v6.62.103: Patrick: 'das kommt jedes Mal wenn ich eine Fahrt ueber die
// Native-App erstelle â€” nervig'. Auto-fixes sollen Patrick NICHT mehr per
// Telegram alarmieren. Nur unresolved Issues alarmieren.
// Eine Issue gilt als "auto-resolved", wenn die NACHFOLGENDE Issue mit
// "â†’ Auto-Fix" oder "-> Auto-Fix" beginnt. Paare werden gefiltert.
async function logDataInconsistency(rideId, ride, issues) {
    const dayKey = getTodayLogKey();
    const entry = {
        t: Date.now(),
        ts: new Date().toLocaleString('de-DE', { timeZone: 'Europe/Berlin' }),
        type: 'data_inconsistency',
        rideId,
        customer: ride?.customerName || '?',
        pickup: ride?.pickup || '?',
        destination: ride?.destination || '?',
        issues,
        version: CLOUD_FUNCTIONS_VERSION
    };

    try {
        await db.ref(`errorLogs/${dayKey}`).push(entry);
    } catch (e) { /* ignore */ }

    // v6.62.103: Auto-fixed Paare aus Admin-Warnung filtern.
    // Heuristik: Eine Issue bei der die naechste mit "Auto-Fix" beginnt
    // (mit beliebigem Prefix wie "â†’" / "->" / Whitespace) ist gefixt â†’ BEIDE
    // raus. Die Lifecycle/errorLogs-Eintraege bleiben fuer Audit.
    const _unresolved = [];
    for (let i = 0; i < issues.length; i++) {
        const cur = issues[i];
        const next = issues[i + 1] || '';
        const _nextIsAutoFix = /(?:^|\s)(?:â†’|->)\s*Auto-Fix/i.test(next) || /^Auto-Fix/i.test(next.replace(/^[\s\-â†’>]+/, ''));
        if (_nextIsAutoFix) {
            i++; // skip the Auto-Fix line too
            continue;
        }
        // Nicht skippen wenn die Issue selbst schon ein Auto-Fix-Folge-Eintrag ist
        if (/(?:^|\s)(?:â†’|->)\s*Auto-Fix/i.test(cur)) continue;
        _unresolved.push(cur);
    }

    // Admin warnen NUR wenn unresolved Issues vorhanden
    if (_unresolved.length > 0) {
        const warnMsg = `âڑ ï¸ڈ <b>DATEN-INKONSISTENZ</b>\n\n` +
            `ًںڑ• Fahrt: <b>${ride?.customerName || '?'}</b>\n` +
            `ًں“چ ${ride?.pickup || '?'} â†’ ${ride?.destination || '?'}\n\n` +
            _unresolved.map(i => `â‌Œ ${i}`).join('\n') +
            `\n\nًں”§ <i>Bitte Fahrt prأ¼fen: ${rideId}</i>`;
        try {
            await sendToAllAdmins(warnMsg);
        } catch (e) { /* ignore */ }
        await addRideLog(rideId, 'âڑ ï¸ڈ', `Daten-Inkonsistenz: ${_unresolved.join(', ')}`);
    } else if (issues.length > 0) {
        // Alles auto-gefixt â†’ nur Audit-Trail im Lifecycle, keine Alarmierung.
        await addRideLog(rideId, 'âœ…', `Konsistenz auto-gefixt`, { count: issues.length, originalIssues: issues });
    }
}

// ًں†• v6.38.44: ErrorLogs automatisch aufrأ¤umen (max 7 Tage behalten)
async function trimErrorLogs() {
    try {
        const snap = await db.ref('errorLogs').once('value');
        const logs = snap.val();
        if (!logs) return;
        const now = new Date();
        const cutoff = new Date(now);
        cutoff.setDate(cutoff.getDate() - 7);
        const cutoffKey = cutoff.toISOString().slice(0, 10);
        for (const dayKey of Object.keys(logs)) {
            if (dayKey < cutoffKey) {
                await db.ref(`errorLogs/${dayKey}`).remove();
                console.log(`ًں§¹ ErrorLogs gelأ¶scht: ${dayKey}`);
            }
        }
    } catch (e) { /* ignore */ }
}

function trimTelegramLogs(currentDay) {
    const rootRef = db.ref('settings/telegram/botlog');
    rootRef.once('value').then(snap => {
        if (!snap.exists()) return;
        const days = [];
        snap.forEach(dayChild => { days.push(dayChild.key); });
        // Alte Tage lأ¶schen (أ¤lter als 7 Tage behalten)
        const cutoffDate = new Date(Date.now() - 7 * 24 * 60 * 60 * 1000).toISOString().slice(0, 10);
        for (const day of days) {
            if (day < cutoffDate) {
                rootRef.child(day).remove().catch(() => {});
            }
        }
        // Heutigen Tag auf max 500 Eintrأ¤ge begrenzen
        const todayRef = rootRef.child(currentDay);
        todayRef.once('value').then(todaySnap => {
            const count = todaySnap.numChildren();
            if (count > 520) {
                const toDelete = count - 500;
                let deleted = 0;
                todaySnap.forEach(child => {
                    if (deleted < toDelete) { child.ref.remove(); deleted++; }
                });
            }
        }).catch(() => {});
    }).catch(() => {});
}

