// ًں†• v6.16.3: Admin-Bestأ¤tigung fأ¼r Kunden-أ„nderungen an Fahrten
// Speichert die gewأ¼nschte أ„nderung als pendingChange und schickt Admin eine Bestأ¤tigungs-Nachricht
async function requestAdminApprovalForRideChange(customerChatId, rideId, changeType, changeData, rideInfo) {
    const changeId = `chg_${Date.now()}_${Math.random().toString(36).substr(2, 6)}`;

    // أ„nderung in Firebase speichern (pendingChanges)
    await db.ref(`settings/telegram/pendingChanges/${changeId}`).set({
        rideId,
        customerChatId: String(customerChatId),
        changeType, // 'time', 'date', 'pickup', 'destination'
        changeData, // Die Update-Daten fأ¼r Firebase
        rideInfo,   // Anzeige-Infos (aktuelle Fahrtdaten)
        createdAt: Date.now(),
        status: 'pending'
    });

    // Admin-Nachricht zusammenbauen
    let changeDesc = '';
    if (changeType === 'time') {
        changeDesc = `âڈ° <b>Neue Uhrzeit:</b> ${changeData.pickupTime} Uhr`;
    } else if (changeType === 'date') {
        changeDesc = `ًں“… <b>Neues Datum:</b> ${changeData.pickupDate}\nâڈ° <b>Uhrzeit bleibt:</b> ${changeData.pickupTime} Uhr`;
    } else if (changeType === 'pickup') {
        changeDesc = `ًں“چ <b>Neuer Abholort:</b> ${changeData.pickup}`;
    } else if (changeType === 'destination') {
        changeDesc = `ًںژ¯ <b>Neues Ziel:</b> ${changeData.destination}`;
    }

    const adminMsg = `ًں”” <b>أ„nderungsanfrage von Kunde!</b>\n\n` +
        `ًں‘¤ ${rideInfo.customerName || 'Kunde'}\n` +
        `ًں“… ${rideInfo.dateStr} um ${rideInfo.timeStr} Uhr\n` +
        `ًں“چ ${rideInfo.pickup || '?'} â†’ ${rideInfo.destination || '?'}\n\n` +
        `${changeDesc}\n\n` +
        `<b>أ„nderung bestأ¤tigen?</b>`;

    // An alle Admins senden (mit Kategorie-Filter)
    const adminSnap = await db.ref('settings/telegram/adminChats').once('value');
    const adminChats = adminSnap.val() || [];
    for (const adminChatId of adminChats) {
        try {
            const prefs = await getAdminNotifyPrefs(adminChatId);
            if (prefs && prefs.change_request === false) continue;
            await sendTelegramMessage(adminChatId, adminMsg, {
                reply_markup: { inline_keyboard: [
                    [
                        { text: 'âœ… Bestأ¤tigen', callback_data: `approve_chg_${changeId}` },
                        { text: 'â‌Œ Ablehnen', callback_data: `reject_chg_${changeId}` }
                    ]
                ]}
            });
        } catch (e) { console.error('Admin-Benachrichtigung fehlgeschlagen:', e.message); }
    }

    // Kunde informieren, dass أ„nderung zur Bestأ¤tigung weitergeleitet wurde
    await sendTelegramMessage(customerChatId,
        `âڈ³ <b>أ„nderung angefragt!</b>\n\n${changeDesc}\n\n<i>Ihre Anfrage wurde an die Zentrale weitergeleitet. Sie erhalten eine Bestأ¤tigung sobald die أ„nderung genehmigt wird.</i>`
    );

    await addTelegramLog('ًں””', customerChatId, `أ„nderungsanfrage: ${changeType} fأ¼r Fahrt ${rideId}`);
    return changeId;
}

