            const dateVal = `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, '0')}-${String(d.getDate()).padStart(2, '0')}`;
            dateButtons.push({ text: dayLabel, callback_data: `adm_setdate_${rideId}_${dateVal}` });
