        const statusLabels = { sofort: 'âڑ، Sofortfahrt', open: 'ًں“‹ Offen', new: 'ًں“‹ Offen', pending: 'ًں“‹ Offen', vorbestellt: 'ًں“… Vorbestellt', assigned: 'ًںژ¯ Vorgesehen', accepted: 'âœ… Akzeptiert', unterwegs: 'ًںڑ— Unterwegs', on_way: 'ًںڑ— Unterwegs', picked_up: 'ًں‘¤ Besetzt', abgeschlossen: 'ًںڈپ Abgeschlossen', completed: 'ًںڈپ Abgeschlossen', deleted: 'ًں—‘ï¸ڈ Gelأ¶scht', storniert: 'â‌Œ Storniert', cancelled: 'â‌Œ Storniert' };
