async function getAdminNotifyPrefs(chatId) {
    try {
        const snap = await db.ref(`settings/telegram/adminNotifyPrefs/${chatId}`).once('value');
        return snap.val() || null; // null = alle aktiv (Standard)
    } catch (e) { return null; }
}

async function sendToAllAdmins(message, category) {
    try {
        const snapshot = await db.ref('settings/telegram/adminChats').once('value');
        const _raw = snapshot.val();
        // ًں”§ v6.38.43: Firebase gibt Arrays manchmal als Objekte zurأ¼ck â†’ normalisieren
        const adminChats = Array.isArray(_raw) ? _raw : (typeof _raw === 'object' && _raw !== null ? Object.values(_raw) : (_raw ? [_raw] : []));
        if (adminChats.length === 0) {
            console.log('âڑ ï¸ڈ Keine Telegram-Admin-Chats konfiguriert');
            return;
        }
        console.log(`ًں“¢ sendToAllAdmins: ${adminChats.length} Admins, Kategorie: ${category || 'alle'}`);
        for (const chatId of adminChats) {
            // ًں”” v6.20.1: Kategorie-Filter prأ¼fen
            // ًں†• v6.62.68: Master-Toggle status_change wirkt OFF auf alle status_* Sub-Kategorien
            if (category) {
                const prefs = await getAdminNotifyPrefs(chatId);
                if (prefs) {
                    if (prefs[category] === false) {
                        console.log(`ًں”• Admin ${chatId}: Kategorie '${category}' deaktiviert`);
                        continue;
                    }
                    // Master-Logik: status_change OFF â†’ alle status_* aus
                    if (category.startsWith('status_') && category !== 'status_change' && prefs.status_change === false) {
                        console.log(`ًں”• Admin ${chatId}: Master 'status_change' OFF â†’ '${category}' uebersprungen`);
                        continue;
                    }
                }
            }
            const result = await sendTelegramMessage(chatId, message);
            if (!result) console.error(`â‌Œ sendToAllAdmins: Nachricht an ${chatId} fehlgeschlagen`);
        }
    } catch (e) {
        console.error('â‌Œ sendToAllAdmins Fehler:', e.message, e.stack);
    }
}

