// ًں†• v6.25.4: WhatsApp Business API â€” Rechnung als PDF-Anhang senden
// â•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گ

exports.sendInvoiceWhatsApp = onRequest(
    { region: 'europe-west1', timeoutSeconds: 60, invoker: 'public' },
    async (req, res) => {
        res.set('Access-Control-Allow-Origin', '*');
        res.set('Access-Control-Allow-Methods', 'POST, OPTIONS');
        res.set('Access-Control-Allow-Headers', 'Content-Type');
        if (req.method === 'OPTIONS') { res.status(204).send(''); return; }

        if (req.method !== 'POST') {
            res.status(405).json({ error: 'Method not allowed' });
            return;
        }

        try {
            const { invoiceNumber, phone, customerName, amount, pdfUrl } = req.body;

            if (!invoiceNumber || !phone || !pdfUrl) {
                res.status(400).json({ error: 'invoiceNumber, phone und pdfUrl sind erforderlich' });
                return;
            }

            // WhatsApp Business API Credentials aus Firebase laden
            const tokenSnap = await db.ref('settings/whatsapp/apiToken').once('value');
            const phoneIdSnap = await db.ref('settings/whatsapp/phoneNumberId').once('value');
            const apiToken = tokenSnap.val();
            const apiPhoneId = phoneIdSnap.val();

            if (!apiToken || !apiPhoneId) {
                res.status(400).json({ error: 'WhatsApp Business API nicht konfiguriert! Bitte apiToken und phoneNumberId unter settings/whatsapp eintragen.' });
                return;
            }

            // Telefonnummer formatieren (international ohne +)
            let formattedPhone = phone.replace(/[\s\-\/\(\)]/g, '');
            if (formattedPhone.startsWith('0')) {
                formattedPhone = '49' + formattedPhone.substring(1);
            } else if (formattedPhone.startsWith('+')) {
                formattedPhone = formattedPhone.substring(1);
            }

            const waApiUrl = `https://graph.facebook.com/v21.0/${apiPhoneId}/messages`;

            // Schritt 1: PDF als Dokument senden
            console.log(`ًں“¤ Sende PDF an ${formattedPhone}...`);
            const docResponse = await fetch(waApiUrl, {
                method: 'POST',
                headers: {
                    'Authorization': `Bearer ${apiToken}`,
                    'Content-Type': 'application/json'
                },
                body: JSON.stringify({
                    messaging_product: 'whatsapp',
                    to: formattedPhone,
                    type: 'document',
                    document: {
                        link: pdfUrl,
                        filename: `Rechnung-${invoiceNumber}.pdf`,
                        caption: `ًں“„ Rechnung Nr. ${invoiceNumber} أ¼ber ${parseFloat(amount || 0).toFixed(2)} â‚¬\n\nVielen Dank!\nTaxi Patrick Wydra\nًں“‍ 038378/22022`
                    }
                })
            });

            const docResult = await docResponse.json();

            if (!docResponse.ok) {
                console.error('â‌Œ WhatsApp API Fehler:', JSON.stringify(docResult));
                res.status(docResponse.status).json({
                    error: 'WhatsApp API Fehler',
                    details: docResult
                });
                return;
            }

            console.log('âœ… PDF per WhatsApp gesendet:', docResult.messages?.[0]?.id);

            // In Firebase loggen
            await db.ref(`invoices/${invoiceNumber}`).update({
                whatsappSentAt: Date.now(),
                whatsappSentTo: formattedPhone,
                whatsappMessageId: docResult.messages?.[0]?.id || null,
                invoiceSentVia: 'whatsapp_api'
            });

            // Protokoll
            await db.ref('emailLog').push({
                type: 'whatsapp_invoice',
                invoiceNumber,
                to: formattedPhone,
                customerName: customerName || '',
                amount: amount || 0,
                messageId: docResult.messages?.[0]?.id || null,
                status: 'sent',
                sentAt: Date.now()
            });

            res.status(200).json({
                success: true,
                messageId: docResult.messages?.[0]?.id,
                to: formattedPhone
            });

        } catch (error) {
            console.error('â‌Œ WhatsApp Rechnung Fehler:', error.message);
            res.status(500).json({ error: error.message });
        }
    }
);

// â•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گ
// CRM E-Mails
// â•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گ

exports.sendCrmEmail = onRequest(
    { region: 'europe-west1', timeoutSeconds: 60, invoker: 'public' },
    async (req, res) => {
        // CORS
        res.set('Access-Control-Allow-Origin', '*');
        res.set('Access-Control-Allow-Methods', 'POST, OPTIONS');
        res.set('Access-Control-Allow-Headers', 'Content-Type');
        if (req.method === 'OPTIONS') { res.status(204).send(''); return; }

        if (req.method !== 'POST') {
            res.status(405).json({ error: 'Method not allowed' });
            return;
        }

        try {
            const {
                to,
                toName,
                subject,
                htmlBody,
                replyTo,    // Optional: Antwort-Adresse (z.B. Kunden-Email bei Anfragen)
                attachment  // Optional: { filename, content (base64), contentType }
            } = req.body;

            if (!to || !subject) {
                res.status(400).json({ error: 'to und subject sind erforderlich' });
                return;
            }

            // SMTP-Einstellungen aus Firebase laden
            const smtpSnap = await db.ref('settings/smtp').once('value');
            const smtp = smtpSnap.val();

            if (!smtp || !smtp.host || !smtp.user || !smtp.pass) {
                res.status(400).json({ error: 'SMTP nicht konfiguriert! Bitte unter CRM â†’ Einstellungen â†’ SMTP einrichten.' });
                return;
            }

            const nodemailer = require('nodemailer');
            const transporter = nodemailer.createTransport({
                host: smtp.host,
                port: parseInt(smtp.port) || 587,
                secure: (parseInt(smtp.port) || 587) === 465,
                auth: { user: smtp.user, pass: smtp.pass }
            });

            // E-Mail-Optionen
            const mailOptions = {
                from: `"${smtp.fromName || 'Taxi Wydra'}" <${smtp.fromEmail || smtp.user}>`,
                to: toName ? `"${toName}" <${to}>` : to,
                subject: subject,
                html: htmlBody || `<p>${subject}</p>`,
                ...(replyTo && { replyTo: replyTo })
            };

            // Anhang hinzufأ¼gen wenn vorhanden
            if (attachment && attachment.content && attachment.filename) {
                mailOptions.attachments = [{
                    filename: attachment.filename,
                    content: Buffer.from(attachment.content, 'base64'),
                    contentType: attachment.contentType || 'application/octet-stream'
                }];
            }

            const info = await transporter.sendMail(mailOptions);
            console.log(`ًں“§ CRM E-Mail gesendet â†’ ${to} (${subject})`, info.messageId);

            // In emailLog speichern
            await db.ref('emailLog').push({
                type: 'crm-manual',
                to: to,
                subject: subject,
                sentAt: Date.now(),
                messageId: info.messageId,
                hasAttachment: !!(attachment && attachment.filename),
                attachmentName: attachment?.filename || null
            });

            res.status(200).json({ success: true, messageId: info.messageId });

        } catch (error) {
            console.error('â‌Œ CRM E-Mail Fehler:', error.message);
            res.status(500).json({ error: error.message });
        }
    }
);

// â•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گ
// ًں†• v6.38.43: Tأ„GLICHE SYSTEMKONTROLLE
// Prأ¼ft jeden Morgen um 06:00 auf Unstimmigkeiten im System
// â•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گ

exports.dailySystemCheck = onSchedule(
    {
        schedule: 'every day 06:00',
        timeZone: 'Europe/Berlin',
        region: 'europe-west1',
        timeoutSeconds: 120,
        memory: '256MiB'
    },
    async (event) => {
        console.log('ًں”چ Tأ¤gliche Systemkontrolle gestartet...');
        const now = Date.now();
        const today = new Date(now);
        const todayStr = today.toLocaleDateString('de-DE', { timeZone: 'Europe/Berlin', day: '2-digit', month: '2-digit', year: '2-digit' });
        const issues = [];
        const stats = { rides: 0, vehicles: 0, customers: 0, pendings: 0 };

        try {
            // â•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گ
            // 1. FAHRTEN-KONSISTENZ
            // â•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گ
            const ridesSnap = await db.ref('rides').once('value');
            const rides = ridesSnap.val() || {};
            stats.rides = Object.keys(rides).length;

            let zombieRides = 0;         // Fahrten ohne Status
            let orphanedRides = 0;       // Fahrten mit gelأ¶schtem Fahrzeug
            let pastOpenRides = 0;       // Offene Fahrten in der Vergangenheit
            let duplicateVehicle = {};   // Fahrzeug doppelt zugewiesen zur gleichen Zeit
            let missingCoords = 0;       // Fahrten ohne Koordinaten
            let missingPrice = 0;        // Fahrten ohne Preis
            let stuckPending = 0;        // Fahrten mit Status "new" > 2h alt

            for (const [rideId, ride] of Object.entries(rides)) {
                // Zombie-Rides (kein Status)
                if (!ride.status) {
                    zombieRides++;
                    issues.push(`ًں§ں Fahrt ${rideId} ohne Status (${ride.customerName || '?'})`);
                }

                // Vergangene offene Fahrten (> 2h in der Vergangenheit, noch "new" oder "vorbestellt")
                if (['new', 'vorbestellt', 'warteschlange'].includes(ride.status)) {
                    const pickupTs = ride.pickupTimestamp || ride.createdAt || 0;
                    if (pickupTs > 0 && pickupTs < now - 2 * 3600000) {
                        pastOpenRides++;
                        const age = Math.round((now - pickupTs) / 3600000);
                        issues.push(`âڈ° Fahrt ${rideId} "${ride.status}" â€” ${age}h أ¼berfأ¤llig (${ride.customerName || '?'}: ${ride.pickup || '?'} â†’ ${ride.destination || '?'})`);
                    }
                }

                // Steckengebliebene "new" Fahrten (> 2h, kein Fahrzeug)
                if (ride.status === 'new' && !ride.assignedVehicle && ride.createdAt && ride.createdAt < now - 2 * 3600000) {
                    stuckPending++;
                }

                // Aktive Fahrten ohne Koordinaten
                if (!['completed', 'cancelled', 'deleted', 'rejected'].includes(ride.status)) {
                    if (!ride.pickupLat || !ride.destinationLat) {
                        missingCoords++;
                    }
                    if (!ride.price && !ride.estimatedPrice) {
                        missingPrice++;
                    }
                }

                // Fahrzeug-Doppelbelegung prأ¼fen (nur aktive Fahrten)
                if (ride.assignedVehicle && !['completed', 'cancelled', 'deleted', 'rejected'].includes(ride.status)) {
                    const vKey = ride.assignedVehicle;
                    if (!duplicateVehicle[vKey]) duplicateVehicle[vKey] = [];
                    duplicateVehicle[vKey].push({
                        rideId,
                        pickupTs: ride.pickupTimestamp || ride.createdAt,
                        duration: ride.duration || ride.estimatedDuration || 30,
                        customer: ride.customerName || '?'
                    });
                }
            }

            // Zeitkonflikte finden
            for (const [vehicleId, vehicleRides] of Object.entries(duplicateVehicle)) {
                if (vehicleRides.length < 2) continue;
                vehicleRides.sort((a, b) => (a.pickupTs || 0) - (b.pickupTs || 0));
                for (let i = 0; i < vehicleRides.length - 1; i++) {
                    const current = vehicleRides[i];
                    const next = vehicleRides[i + 1];
                    const currentEnd = (current.pickupTs || 0) + (current.duration || 30) * 60000;
                    if (next.pickupTs && next.pickupTs < currentEnd) {
                        const vName = (OFFICIAL_VEHICLES[vehicleId] || {}).name || vehicleId;
                        issues.push(`âڑ، ZEITKONFLIKT: ${vName} â€” ${current.customer} (${current.rideId}) und ${next.customer} (${next.rideId}) أ¼berlappen!`);
                    }
                }
            }

            if (zombieRides > 0) issues.push(`ًں§ں ${zombieRides} Fahrten ohne Status`);
            if (stuckPending > 0) issues.push(`ًں”’ ${stuckPending} Fahrten seit >2h im Status "new" ohne Fahrzeug`);
            if (missingCoords > 0) issues.push(`ًں“چ ${missingCoords} aktive Fahrten ohne Koordinaten`);
            if (missingPrice > 0) issues.push(`ًں’° ${missingPrice} aktive Fahrten ohne Preis`);

            // â•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گ
            // 2. FAHRZEUG-STATUS
            // â•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گ
            const vehiclesSnap = await db.ref('vehicles').once('value');
            const vehicles = vehiclesSnap.val() || {};
            stats.vehicles = Object.keys(vehicles).length;

            for (const [vId, vehicle] of Object.entries(vehicles)) {
                // GPS veraltet (> 24h ohne Update bei "online" Fahrzeug)
                if (vehicle.isOnline && vehicle.lastUpdate) {
                    const gpsAge = now - vehicle.lastUpdate;
                    if (gpsAge > 24 * 3600000) {
                        const hours = Math.round(gpsAge / 3600000);
                        issues.push(`ًں“، Fahrzeug ${vehicle.name || vId} "online" aber GPS seit ${hours}h veraltet`);
                    }
                }
            }

            // â•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گ
            // 3. TELEGRAM PENDINGS (hأ¤ngengebliebene Buchungen)
            // â•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گ
            const pendingSnap = await db.ref('settings/telegram/pending').once('value');
            const pendings = pendingSnap.val() || {};
            stats.pendings = Object.keys(pendings).length;
            let stalePendings = 0;

            for (const [chatId, pending] of Object.entries(pendings)) {
                const age = pending.createdAt ? (now - pending.createdAt) : 0;
                // أ„lter als 6 Stunden â†’ wahrscheinlich hأ¤ngengeblieben
                if (age > 6 * 3600000 || (!pending.createdAt && pending.partial)) {
                    stalePendings++;
                    const name = (pending.partial || {}).name || chatId;
                    const ageH = age ? `${Math.round(age / 3600000)}h` : 'unbekannt';
                    issues.push(`ًں”’ Telegram-Pending hأ¤ngt: ${name} (Chat ${chatId}, Alter: ${ageH})`);
                }
            }

            if (stalePendings > 0) {
                issues.push(`ًں“± ${stalePendings} hأ¤ngengebliebene Telegram-Buchungen â†’ automatisch bereinigt`);
                // Auto-Cleanup: Pendings > 24h lأ¶schen
                for (const [chatId, pending] of Object.entries(pendings)) {
                    const age = pending.createdAt ? (now - pending.createdAt) : 0;
                    if (age > 24 * 3600000) {
                        await db.ref(`settings/telegram/pending/${chatId}`).remove();
                        console.log(`ًں§¹ Stale Pending gelأ¶scht: ${chatId}`);
                    }
                }
            }

            // â•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گ
            // 4. CRM-DATEN-QUALITأ„T
            // â•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گ
            const customersSnap = await db.ref('customers').once('value');
            const customers = customersSnap.val() || {};
            stats.customers = Object.keys(customers).length;

            let noPhone = 0;
            let noAddress = 0;
            let duplicatePhones = {};

            for (const [cId, cust] of Object.entries(customers)) {
                if (!cust.phone && !cust.mobilePhone) noPhone++;
                if (!cust.address && !cust.street) noAddress++;

                // Telefon-Duplikate finden
                const phones = [cust.phone, cust.mobilePhone].filter(p => p);
                for (const p of phones) {
                    const normalized = String(p).replace(/\D/g, '').slice(-9);
                    if (normalized.length >= 8) {
                        if (!duplicatePhones[normalized]) duplicatePhones[normalized] = [];
                        duplicatePhones[normalized].push(cust.name || cId);
                    }
                }
            }

            const dupes = Object.entries(duplicatePhones).filter(([_, names]) => names.length > 1);
            if (dupes.length > 0) {
                issues.push(`ًں‘¥ ${dupes.length} mأ¶gliche CRM-Duplikate (gleiche Telefonnummer):`);
                dupes.slice(0, 5).forEach(([phone, names]) => {
                    issues.push(`   â†³ ...${phone}: ${names.join(' / ')}`);
                });
                if (dupes.length > 5) issues.push(`   â†³ ...und ${dupes.length - 5} weitere`);
            }

            // â•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گ
            // 5. RECHNUNGEN PRأœFEN
            // â•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گ
            const invoicesSnap = await db.ref('invoices').once('value');
            const invoices = invoicesSnap.val() || {};
            let unpaidInvoices = 0;
            let missingPdf = 0;

            for (const [invId, inv] of Object.entries(invoices)) {
                if (inv.status === 'offen' || inv.status === 'open') unpaidInvoices++;
                if (!inv.pdfUrl) missingPdf++;
            }

            if (unpaidInvoices > 0) issues.push(`ًں’¶ ${unpaidInvoices} offene/unbezahlte Rechnungen`);
            if (missingPdf > 0) issues.push(`ًں“„ ${missingPdf} Rechnungen ohne PDF`);

            // â•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گ
            // 6. HEUTIGE FAHRTEN ZUSAMMENFASSUNG
            // â•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گ
            const todayStart = new Date(today.toLocaleDateString('en-US', { timeZone: 'Europe/Berlin' })).getTime();
            const todayEnd = todayStart + 24 * 3600000;

            let todayRides = 0;
            let todayUnassigned = 0;
            let todayCompleted = 0;

            for (const [rideId, ride] of Object.entries(rides)) {
                const rideTs = ride.pickupTimestamp || ride.createdAt || 0;
                if (rideTs >= todayStart && rideTs < todayEnd) {
                    todayRides++;
                    if (!ride.assignedVehicle && !['completed', 'cancelled', 'deleted'].includes(ride.status)) {
                        todayUnassigned++;
                    }
                    if (ride.status === 'completed') todayCompleted++;
                }
            }

            // â•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گ
            // 7. ERROR-LOG ZUSAMMENFASSUNG (letzte 24h)
            // â•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گ
            let errorCount24h = 0;
            let criticalErrors24h = 0;
            let topErrorFunctions = {};
            try {
                const yesterdayKey = new Date(now - 86400000).toISOString().slice(0, 10);
                const todayKey = getTodayLogKey();
                for (const dayKey of [yesterdayKey, todayKey]) {
                    const errSnap = await db.ref(`errorLogs/${dayKey}`).once('value');
                    const errLogs = errSnap.val() || {};
                    for (const [, entry] of Object.entries(errLogs)) {
                        if (entry.t && entry.t > now - 86400000) {
                            errorCount24h++;
                            if (entry.severity === 'critical') criticalErrors24h++;
                            if (entry.fn) {
                                topErrorFunctions[entry.fn] = (topErrorFunctions[entry.fn] || 0) + 1;
                            }
                        }
                    }
                }
                if (errorCount24h > 0) {
                    issues.push(`ًں”´ ${errorCount24h} Fehler in den letzten 24h (${criticalErrors24h} kritisch)`);
                    // Top-3 Fehlerquellen
                    const topErrors = Object.entries(topErrorFunctions).sort((a, b) => b[1] - a[1]).slice(0, 3);
                    for (const [fn, count] of topErrors) {
                        issues.push(`   â†³ ${fn}: ${count}x`);
                    }
                }
                // ErrorLogs aufrأ¤umen (max 7 Tage)
                await trimErrorLogs();
            } catch (e) {
                console.warn('âڑ ï¸ڈ ErrorLog-Zusammenfassung fehlgeschlagen:', e.message);
            }

            // â•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گ
            // BERICHT SENDEN
            // â•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گ
            const statusEmoji = issues.length === 0 ? 'âœ…' : (issues.length <= 3 ? 'âڑ ï¸ڈ' : 'ًں”´');
            const header = `${statusEmoji} <b>Tأ„GLICHER SYSTEMBERICHT</b>\nًں“… ${todayStr} آ· 06:00 Uhr\n`;

            const statsBlock = `ًں“ٹ <b>System-Status:</b>\n` +
                `   ًںڑ• ${stats.rides} Fahrten gesamt\n` +
                `   ًں“… ${todayRides} Fahrten heute (${todayCompleted} erledigt, ${todayUnassigned} ohne Fahrer)\n` +
                `   ًںڑ— ${stats.vehicles} Fahrzeuge\n` +
                `   ًں‘¥ ${stats.customers} CRM-Kunden\n` +
                `   ًں“± ${stats.pendings} aktive Telegram-Buchungen\n` +
                (errorCount24h > 0 ? `   ًں”´ ${errorCount24h} Fehler (${criticalErrors24h} kritisch)\n` : `   âœ… Keine Fehler in 24h\n`);

            let report;
            if (issues.length === 0) {
                report = header + '\n' + statsBlock + '\nâœ… <b>Keine Unstimmigkeiten gefunden!</b>\n\nًںژ‰ System lأ¤uft einwandfrei.';
            } else {
                report = header + '\n' + statsBlock +
                    `\nâڑ ï¸ڈ <b>${issues.length} Unstimmigkeiten gefunden:</b>\n\n` +
                    issues.map((issue, i) => `${i + 1}. ${issue}`).join('\n') +
                    `\n\nًں’، <i>Bitte prأ¼fen und ggf. korrigieren.</i>`;
            }

            // An alle Admins senden
            await sendToAllAdmins(report, 'system_check');
            await sendToSystemChannel(report, 'system_check');

            console.log(`âœ… Systemkontrolle abgeschlossen: ${issues.length} Probleme gefunden`);

            // In Firebase loggen
            await db.ref('settings/systemCheck').update({
                lastRun: now,
                issuesCount: issues.length,
                issues: issues.slice(0, 20), // Max 20 speichern
                stats: stats,
                todayRides: todayRides,
                todayUnassigned: todayUnassigned
            });

        } catch (err) {
            console.error('â‌Œ Systemkontrolle Fehler:', err.message, err.stack);
            await logError('dailySystemCheck', err, { severity: 'critical' });
            try {
                await sendToAllAdmins(`â‌Œ <b>Systemkontrolle fehlgeschlagen!</b>\n\nFehler: ${err.message}\n\n<i>Fehlerlog: Firebase â†’ errorLogs</i>`);
            } catch (_) {}
        }
    }
);

// â•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گ
// ًں†• v6.38.44: FEHLERANALYSE-DASHBOARD (HTTP-Endpunkt)
// Zeigt alle Fehler der letzten 7 Tage als JSON oder HTML
// â•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گ

exports.errorDashboard = onRequest(
    { region: 'europe-west1', invoker: 'public' },
    async (req, res) => {
        res.set('Access-Control-Allow-Origin', '*');
        res.set('Access-Control-Allow-Methods', 'GET, OPTIONS');
        res.set('Access-Control-Allow-Headers', 'Content-Type');
        if (req.method === 'OPTIONS') { res.status(204).send(''); return; }

        // Admin-Check (Telegram-Webhook-Secret als Key)
        const key = req.query.key;
        const secretSnap = await db.ref('settings/telegram/webhookSecret').once('value');
        const secret = secretSnap.val();
        if (!key || key !== secret) {
            res.status(403).json({ error: 'Nicht autorisiert. ?key= Parameter fehlt oder falsch.' });
            return;
        }

        const format = req.query.format || 'html';
        const days = Math.min(parseInt(req.query.days) || 3, 7);

        // ErrorLogs laden
        const allErrors = [];
        const now = new Date();
        for (let i = 0; i < days; i++) {
            const d = new Date(now);
            d.setDate(d.getDate() - i);
            const dayKey = d.toISOString().slice(0, 10);
            try {
                const snap = await db.ref(`errorLogs/${dayKey}`).once('value');
                const logs = snap.val() || {};
                for (const [id, entry] of Object.entries(logs)) {
                    allErrors.push({ id, dayKey, ...entry });
                }
            } catch (e) { /* skip */ }
        }

        allErrors.sort((a, b) => (b.t || 0) - (a.t || 0));

        if (format === 'json') {
            res.status(200).json({ total: allErrors.length, days, errors: allErrors.slice(0, 200) });
            return;
        }

        // Statistiken
        const bySeverity = { critical: 0, error: 0, warning: 0, data_inconsistency: 0 };
        const byFunction = {};
        for (const e of allErrors) {
            const sev = e.type === 'data_inconsistency' ? 'data_inconsistency' : (e.severity || 'error');
            bySeverity[sev] = (bySeverity[sev] || 0) + 1;
            const fn = e.fn || e.type || '?';
            byFunction[fn] = (byFunction[fn] || 0) + 1;
        }
        const topFunctions = Object.entries(byFunction).sort((a, b) => b[1] - a[1]).slice(0, 10);

        // HTML
        const html = `<!DOCTYPE html><html lang="de"><head>
<meta charset="UTF-8"><meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Fehleranalyse â€” Taxi Heringsdorf</title>
<style>
body{font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',sans-serif;margin:0;padding:20px;background:#1a1a2e;color:#eee}
h1{color:#e94560}h2{color:#fff;background:#0f3460;padding:8px 16px;border-radius:8px;display:inline-block}
.stats{display:flex;gap:16px;flex-wrap:wrap;margin:20px 0}
.stat{background:#16213e;padding:16px;border-radius:12px;min-width:120px;text-align:center}
.stat .num{font-size:2em;font-weight:bold}
.stat.critical .num{color:#e94560}.stat.error .num{color:#ff9800}
.stat.warning .num{color:#ffc107}.stat.data .num{color:#2196f3}
.error-list{margin:20px 0}
.error-item{background:#16213e;padding:12px 16px;border-radius:8px;margin:8px 0;border-left:4px solid #666}
.error-item.critical{border-left-color:#e94560}.error-item.error{border-left-color:#ff9800}
.error-item.warning{border-left-color:#ffc107}.error-item.data_inconsistency{border-left-color:#2196f3}
.meta{color:#888;font-size:.85em}.fn{color:#00d2ff;font-weight:bold}
.msg{color:#ff6b6b;margin:4px 0}
pre{background:#0a0a1a;padding:8px;border-radius:4px;overflow-x:auto;font-size:.8em;color:#888;max-height:100px}
.top-fn{display:flex;gap:8px;flex-wrap:wrap}
.fn-badge{background:#16213e;padding:6px 12px;border-radius:20px;font-size:.85em}
.fn-count{color:#e94560;font-weight:bold}
.refresh{background:#e94560;color:#fff;border:none;padding:10px 20px;border-radius:8px;cursor:pointer;font-size:1em;margin:10px 0}
</style></head><body>
<h1>ًں”چ Fehleranalyse-Dashboard v${CLOUD_FUNCTIONS_VERSION}</h1>
<p>Zeitraum: letzte ${days} Tage آ· ${allErrors.length} Eintrأ¤ge آ· <button class="refresh" onclick="location.reload()">ًں”„ Aktualisieren</button></p>
<div class="stats">
<div class="stat critical"><div class="num">${bySeverity.critical}</div>Kritisch</div>
<div class="stat error"><div class="num">${bySeverity.error}</div>Fehler</div>
<div class="stat warning"><div class="num">${bySeverity.warning}</div>Warnungen</div>
<div class="stat data"><div class="num">${bySeverity.data_inconsistency}</div>Daten-Fehler</div>
</div>
<h2>Top Fehlerquellen</h2>
<div class="top-fn">
${topFunctions.map(([fn, count]) => '<span class="fn-badge">' + fn + ': <span class="fn-count">' + count + 'x</span></span>').join('\n')}
</div>
<h2>Fehlerlog (neueste zuerst)</h2>
<div class="error-list">
${allErrors.slice(0, 50).map(e => {
    const sev = e.type === 'data_inconsistency' ? 'data_inconsistency' : (e.severity || 'error');
    const sevIcon = sev === 'critical' ? 'ًں”´' : (sev === 'error' ? 'ًںں ' : (sev === 'warning' ? 'ًںں،' : 'ًں”µ'));
    return '<div class="error-item ' + sev + '">' +
'<div class="meta">' + sevIcon + ' ' + (e.ts || new Date(e.t).toLocaleString('de-DE')) + ' آ· <span class="fn">' + (e.fn || e.type || '?') + '</span>' + (e.chatId ? ' آ· Chat: ' + e.chatId : '') + (e.rideId ? ' آ· Ride: ' + e.rideId : '') + '</div>' +
'<div class="msg">' + ((e.msg || (e.issues || []).join(', ') || '?') + '').substring(0, 200) + '</div>' +
(e.stack ? '<pre>' + (e.stack + '').substring(0, 300) + '</pre>' : '') +
(e.data ? '<pre>Kontext: ' + (e.data + '').substring(0, 200) + '</pre>' : '') +
'</div>';
}).join('\n')}
</div>
<p class="meta">JSON: ?format=json&days=${days}&key=... آ· Max 7 Tage آ· Auto-Cleanup</p>
</body></html>`;

        res.status(200).send(html);
    }
);

// â•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گ
// ًں†• v6.38.44: ECHTZEIT-KONSISTENZ-PRأœFUNG bei Fahrt-Erstellung
// Prأ¼ft sofort ob Strecke/Preis/Koordinaten konsistent sind
// â•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گ

async function validateRideConsistency(rideId, ride) {
    const issues = [];

    // 1. Koordinaten vorhanden aber kein Preis?
    if (ride.pickupLat && ride.destinationLat && !ride.price && !ride.estimatedPrice) {
        issues.push('Preis fehlt trotz vorhandener Koordinaten');
        try {
            const route = await calculateTelegramRoutePrice({
                pickupLat: ride.pickupLat, pickupLon: ride.pickupLon,
                destinationLat: ride.destinationLat, destinationLon: ride.destinationLon
            });
            if (route && route.price) {
                await db.ref(`rides/${rideId}`).update({
                    price: route.price, estimatedPrice: route.price,
                    distance: route.distance, estimatedDistance: route.distance,
                    duration: route.duration, estimatedDuration: route.duration,
                    updatedAt: Date.now()
                });
                await addRideLog(rideId, 'ًں”§', `Auto-Fix: Preis/Strecke nachberechnet (${route.price}â‚¬, ${route.distance} km)`, 'validateRideConsistency');
                issues.push('â†’ Auto-Fix: ' + route.price + 'â‚¬, ' + route.distance + ' km berechnet');
            }
        } catch (e) {
            issues.push('â†’ Preis-Auto-Fix fehlgeschlagen: ' + e.message);
        }
    }

    // 2. Preis vorhanden aber keine Strecke?
    if (ride.price && !ride.distance && !ride.estimatedDistance && ride.pickupLat && ride.destinationLat) {
        issues.push('Strecke fehlt trotz Preis und Koordinaten (genau dein Fall!)');
        try {
            const route = await calculateTelegramRoutePrice({
                pickupLat: ride.pickupLat, pickupLon: ride.pickupLon,
                destinationLat: ride.destinationLat, destinationLon: ride.destinationLon
            });
            if (route && route.distance) {
                await db.ref(`rides/${rideId}`).update({
                    distance: route.distance, estimatedDistance: route.distance,
                    duration: route.duration, estimatedDuration: route.duration,
                    updatedAt: Date.now()
                });
                await addRideLog(rideId, 'ًں”§', `Auto-Fix: Strecke nachberechnet (${route.distance} km, ${route.duration} Min)`, 'validateRideConsistency');
                issues.push('â†’ Auto-Fix: ' + route.distance + ' km berechnet');
            }
        } catch (e) {
            issues.push('â†’ Strecke-Auto-Fix fehlgeschlagen: ' + e.message);
        }
    }

    // 3. distance=0 aber estimatedDistance vorhanden â†’ korrigieren
    if ((!ride.distance || ride.distance === 0 || ride.distance === '0') && ride.estimatedDistance && parseFloat(ride.estimatedDistance) > 0) {
        issues.push('distance=0 aber estimatedDistance=' + ride.estimatedDistance + ' vorhanden');
        try {
            await db.ref(`rides/${rideId}`).update({
                distance: parseFloat(ride.estimatedDistance),
                updatedAt: Date.now()
            });
            await addRideLog(rideId, 'ًں”§', 'Auto-Fix: distance=0 -> ' + ride.estimatedDistance + ' km (aus estimatedDistance)', 'validateRideConsistency');
            issues.push('-> Auto-Fix: distance=' + ride.estimatedDistance);
        } catch (e) { /* ignore */ }
    }

    // 3b. price=0 aber estimatedPrice vorhanden â†’ korrigieren
    if ((!ride.price || ride.price === 0 || ride.price === '0') && ride.estimatedPrice && parseFloat(ride.estimatedPrice) > 0) {
        issues.push('price=0 aber estimatedPrice=' + ride.estimatedPrice + ' vorhanden');
        try {
            await db.ref(`rides/${rideId}`).update({
                price: parseFloat(ride.estimatedPrice),
                updatedAt: Date.now()
            });
            await addRideLog(rideId, 'ًں”§', 'Auto-Fix: price=0 -> ' + ride.estimatedPrice + ' (aus estimatedPrice)', 'validateRideConsistency');
            issues.push('-> Auto-Fix: price=' + ride.estimatedPrice);
        } catch (e) { /* ignore */ }
    }

    // 3c. duration falsch niedrig (< 5 Min bei Strecke > 10 km) â†’ Route neu berechnen
    if (ride.pickupLat && ride.destinationLat && ride.estimatedDistance && parseFloat(ride.estimatedDistance) > 10 && ride.duration && parseInt(ride.duration) < 5) {
        issues.push('duration=' + ride.duration + ' Min bei ' + ride.estimatedDistance + ' km Strecke - unrealistisch');
        try {
            const route = await calculateTelegramRoutePrice({
                pickupLat: ride.pickupLat, pickupLon: ride.pickupLon,
                destinationLat: ride.destinationLat, destinationLon: ride.destinationLon
            });
            if (route && route.duration > 5) {
                await db.ref(`rides/${rideId}`).update({
                    duration: route.duration, estimatedDuration: route.duration,
                    updatedAt: Date.now()
                });
                await addRideLog(rideId, 'ًں”§', 'Auto-Fix: duration ' + ride.duration + ' -> ' + route.duration + ' Min (OSRM)', 'validateRideConsistency');
                issues.push('-> Auto-Fix: duration=' + route.duration + ' Min');
            }
        } catch (e) { /* ignore */ }
    }

    // 4. Koordinaten fehlen komplett
    // v6.62.4: Race-Condition-Fix â€” bei frisch erstellten Fahrten (<30s alt) Geocoding-Race
    // tolerieren. Geocoder lأ¤uft async und schreibt lat/lon ~1-2s nach Erstellung.
    // validateRideConsistency triggert direkt nach Create â†’ sieht null â†’ false-positive.
    // Patrick: 'Inkonsistenz wurde gemeldet als ich gebucht habe' â€” exakt dieser Fall.
    const _ageMs = ride.createdAt ? Date.now() - ride.createdAt : 999999;
    const _coordsRaceWindow = _ageMs < 30000; // 30 Sekunden Toleranzfenster
    if (!ride.pickupLat && ride.pickup && !_coordsRaceWindow) {
        issues.push('Abholort ohne Koordinaten: "' + ride.pickup + '"');
    }
    if (!ride.destinationLat && ride.destination && !_coordsRaceWindow) {
        issues.push('Zielort ohne Koordinaten: "' + ride.destination + '"');
    }

    // 5. Status-Konsistenz
    // ًں”§ v6.40.21: respektiere Vorbestellungs-Schwelle â€” Vorbestellung bleibt 'vorbestellt', nicht 'assigned'
    // v6.62.222: Schwelle = 15 + Anfahrt statt pauschal 60 Min (synchron mit scheduledAutoAssign).
    if (ride.assignedVehicle && ride.status === 'new') {
        const _msUntilPickup = ride.pickupTimestamp ? (ride.pickupTimestamp - Date.now()) : 0;
        const _anfMinFix = (ride.drivingTimeToPickup && ride.drivingTimeToPickup > 0) ? ride.drivingTimeToPickup : 10;
        const _isSofort = _msUntilPickup > 0 && _msUntilPickup <= (15 + _anfMinFix) * 60000;
        const _targetStatus = _isSofort ? 'assigned' : 'vorbestellt';
        issues.push('Status "new" aber Fahrzeug zugewiesen (' + ride.assignedVehicle + ')');
        // Auto-Fix
        try {
            await db.ref(`rides/${rideId}/status`).set(_targetStatus);
            await addRideLog(rideId, 'ًں”§', `Auto-Fix: Status new â†’ ${_targetStatus} (Fahrzeug war zugewiesen, ${_isSofort ? 'Sofort' : 'Vorbestellung'})`);
            issues.push(`â†’ Auto-Fix: Status auf "${_targetStatus}" gesetzt`);
        } catch (e) { /* ignore */ }
    }

    // 5. Datum-Konsistenz
    if (ride.pickupTimestamp) {
        const now = Date.now();
        if (ride.pickupTimestamp < now - 48 * 3600000 && !['completed', 'cancelled', 'deleted'].includes(ride.status)) {
            issues.push('Abholzeit >48h in Vergangenheit aber Status: ' + ride.status);
        }
    }

    if (issues.length > 0) {
        await logDataInconsistency(rideId, ride, issues);
    }

    return issues;
}

// â•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گ
// ًں†• v6.62.109: PDF-Auftrag-Import via Anthropic Vision
// Patrick: 'Vetter Touristik schickt PDF mit Pickup/Stopps/Namen â€” KI soll
// das parsen und als Buchungs-Vorschlag zurueckgeben'.
// Aufruf: POST URL mit { fileBase64, mediaType, filename } + ?key=SECRET
// Antwort: { ok: true, parsed: { pickup, destination, waypoints[], passengers,
//           datetime, customer, hint } }
// Patrick bestaetigt im UI bevor die Buchung wirklich angelegt wird.
// â•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گ
exports.importAuftragPdf = onRequest(
    { region: 'europe-west1', invoker: 'public', timeoutSeconds: 120, memory: '512MiB' },
    async (req, res) => {
        res.set('Access-Control-Allow-Origin', '*');
        res.set('Access-Control-Allow-Headers', 'Content-Type');
        if (req.method === 'OPTIONS') { res.status(204).send(''); return; }
        if (req.method !== 'POST') { res.status(405).json({ error: 'POST required' }); return; }
        const key = req.query.key;
        const keySnap = await db.ref('settings/healthCheckKey').once('value');
        const validKey = keySnap.val() || 'funk-taxi-heringsdorf-2026';
        if (!key || key !== validKey) { res.status(403).json({ error: 'Forbidden' }); return; }
        try {
            const body = (typeof req.body === 'object') ? req.body : JSON.parse(req.body || '{}');
            const { fileBase64, mediaType, filename } = body;
            if (!fileBase64) { res.status(400).json({ error: 'fileBase64 required' }); return; }
            const _media = mediaType || 'application/pdf';
            const anthropicKey = await getAnthropicApiKey();
            if (!anthropicKey) { res.status(500).json({ error: 'Kein Anthropic API Key konfiguriert' }); return; }

            // Heutiges Datum als Hint fأ¼r KI (Datum-Auflأ¶sung)
            const _today = new Date().toLocaleDateString('de-DE', { timeZone: 'Europe/Berlin', day: '2-digit', month: '2-digit', year: 'numeric' });
            // ًں†• v6.62.144: trips[]-Array statt singular pickup/destination â€” ein PDF kann
            // Hin- + Rueckfahrt enthalten (zwei Seiten). Plus destinationName fuer den Pax
            // der am Ziel aussteigt (Patrick: 'Frau Bohner beim Seehotel Esplanade fehlt').
            const prompt = `Du bekommst einen Taxi-Auftrag (PDF/Bild, evtl. MEHRSEITIG) eines Hotel-/Touristik-Kunden (z.B. Vetter Touristik, Federpoint, Hotels). Extrahiere ALLE Fahrten als striktes JSON.

Heute ist: ${_today}.

WICHTIG: PDFs koennen 2+ Seiten haben â€” typischerweise eine Seite Hinfahrt, eine Seite Rueckfahrt (oder mehrere unabhaengige Fahrten). ALLE als separate Eintraege im trips-Array zurueckgeben.

Format:
{
  "trips": [
    {
      "pickup": "Hauptabhol-Adresse (z.B. 'Strandhotel Heringsdorf, Delbrueckstr. 5, 17424 Heringsdorf')",
      "pickupName": "Name am Pickup (z.B. 'Frau Mueller', 'Familie Schmidt') â€” falls erkennbar, sonst null",
      "destination": "End-Ziel-Adresse (z.B. 'Interferie Medical Spa, Swinemuende')",
      "destinationName": "Name am Ziel-Drop-off (z.B. 'Frau Bohner') â€” falls erkennbar, sonst null",
      "waypoints": [
        { "address": "Zwischenstopp-Adresse", "name": "Gast/Hotel/Klinik der dort aus-/einsteigt (wenn im Auftrag)" }
      ],
      "passengers": 1,
      "datetime": "YYYY-MM-DDTHH:MM:SS+02:00 (Pickup-Zeit). Bei 'morgen'/'Donnerstag' beziehe auf heute (${_today})",
      "customer": { "name": "Auftraggeber (z.B. Vetter Touristik)", "type": "supplier|hotel|firma|null", "address": "Vollstaendige Anschrift aus Briefkopf/Fusszeile (Strasse, PLZ, Ort) â€” null wenn nicht im PDF", "phone": "Telefonnummer des Auftraggebers â€” null wenn nicht im PDF", "email": "Email des Auftraggebers â€” null wenn nicht im PDF", "taxId": "USt-IdNr / Steuernummer â€” null wenn nicht im PDF", "website": "Webseite â€” null wenn nicht im PDF" },
      "hint": "1 Satz Beschreibung dieser einen Fahrt"
    }
    // weitere trips falls mehrere im PDF
  ],
  "confidence": 0.0-1.0,
  "rawText": "ALLEN sichtbaren Text aus dem Dokument wortgenau extrahiert"
}

Beispiele:
- Federpoint-PDF Seite 1 = Hinfahrt zum Flughafen, Seite 2 = Rueckfahrt â†’ 2 Trips.
- Vetter Touristik mit Sammeltransfer (Pickup im Hotel, 3 Drop-offs) â†’ 1 Trip mit 2 waypoints + destination (mit destinationName).
- Hotel-Anweisung ohne Rueckfahrt â†’ 1 Trip.

Gib NUR JSON zurueck, kein Markdown, kein Pre-/Post-Text. Wenn nur EINE Fahrt: trips-Array mit genau 1 Eintrag. Fehlende Felder: null. Bei mehreren Personen mit unterschiedlichen Adressen jede als waypoint mit name (oder destination mit destinationName fuer den letzten Drop-off).`;

            const visionResp = await callAnthropicAPI(anthropicKey, 'claude-sonnet-4-6', 4000, [{
                role: 'user',
                content: [
                    { type: 'document', source: { type: 'base64', media_type: _media, data: fileBase64 } },
                    { type: 'text', text: prompt }
                ]
            }]);
            const text = (visionResp.content?.[0]?.text || '').trim();
            // JSON aus der Antwort holen â€” Claude gibt manchmal ```json ... ``` zurأ¼ck
            let jsonText = text;
            const jsonMatch = text.match(/```(?:json)?\s*([\s\S]*?)```/);
            if (jsonMatch) jsonText = jsonMatch[1].trim();
            let parsed = null;
            try { parsed = JSON.parse(jsonText); }
            catch (parseErr) {
                console.error('importAuftragPdf JSON-Parse-Fehler:', parseErr.message, 'Text:', text.slice(0, 500));
                res.status(200).json({ ok: false, error: 'KI-Antwort konnte nicht als JSON geparst werden', rawText: text });
                return;
            }
            // ًں†• v6.62.144: Backwards-compat fuer alte UI-Versionen â€” wenn KI nur trips[]
            // zurueckgibt aber kein top-level pickup/destination, kopier den ersten Trip
            // hoch. Neue UI nutzt parsed.trips[]; alte UI nutzt parsed.pickup/destination.
            if (parsed && parsed.trips && Array.isArray(parsed.trips) && parsed.trips.length > 0 && !parsed.pickup) {
                const first = parsed.trips[0];
                parsed = {
                    ...first,
                    trips: parsed.trips,
                    confidence: parsed.confidence ?? first.confidence ?? null,
                    rawText: parsed.rawText ?? null
                };
            }
            // Falls trips fehlt aber pickup da ist (alter Prompt-Stil) â†’ ein-Trip-Array generieren
            if (parsed && !parsed.trips && parsed.pickup) {
                parsed.trips = [{
                    pickup: parsed.pickup, pickupName: parsed.pickupName,
                    destination: parsed.destination, destinationName: parsed.destinationName,
                    waypoints: parsed.waypoints || [], passengers: parsed.passengers || 1,
                    datetime: parsed.datetime, customer: parsed.customer, hint: parsed.hint
                }];
            }
            // ًں†• v6.62.150: Auftraggeber-CRM-Lookup â€” sucht customer.name (z.B. Vetter
            // Touristik) im CRM mit Fuzzy-Match. Wenn Treffer: customerId pro Trip mit
            // anhaengen, damit beim Anlegen der Ride der Auftraggeber verknuepft wird +
            // die Rechnung automatisch an die richtige Adresse geht.
            try {
                const customersSnap = await db.ref('customers').once('value');
                const customers = customersSnap.val() || {};
                const findMatch = (searchName) => {
                    if (!searchName || typeof searchName !== 'string') return null;
                    const sNorm = searchName.toLowerCase().replace(/\s+/g, ' ').trim();
                    if (sNorm.length < 3) return null;
                    let best = null;
                    let bestScore = 0;
                    for (const [cid, c] of Object.entries(customers)) {
                        if (!c || !c.name) continue;
                        const cNorm = String(c.name).toLowerCase().replace(/\s+/g, ' ').trim();
                        let score = 0;
                        if (cNorm === sNorm) score = 100;
                        else if (cNorm.includes(sNorm) || sNorm.includes(cNorm)) score = 80;
                        else {
                            // Token-basiert â€” 'Vetter Touristik' matcht 'Vetter' mit 50%
                            const sTokens = sNorm.split(' ').filter(t => t.length > 2);
                            const cTokens = cNorm.split(' ').filter(t => t.length > 2);
                            const overlap = sTokens.filter(t => cTokens.some(ct => ct.includes(t) || t.includes(ct))).length;
                            if (sTokens.length > 0 && cTokens.length > 0) {
                                score = (overlap / Math.max(sTokens.length, cTokens.length)) * 70;
                            }
                        }
                        // Supplier-Bonus â€” Auftraggeber sind typischerweise type:supplier/hotel
                        if (score > 0 && (c.type === 'supplier' || c.type === 'hotel')) score += 5;
                        if (score > bestScore && score >= 50) {
                            bestScore = score;
                            best = { customerId: cid, customer: c, score };
                        }
                    }
                    return best;
                };
                if (parsed.trips) {
                    parsed.trips.forEach(t => {
                        if (t.customer && t.customer.name) {
                            const m = findMatch(t.customer.name);
                            if (m) {
                                t.customerId = m.customerId;
                                t.customerMatchScore = m.score;
                                t.customerMatchedName = m.customer.name;
                            }
                        }
                    });
                }
                // Top-level Spiegelung fuer Backwards-compat
                if (parsed.trips && parsed.trips[0] && parsed.trips[0].customerId) {
                    parsed.customerId = parsed.trips[0].customerId;
                    parsed.customerMatchScore = parsed.trips[0].customerMatchScore;
                    parsed.customerMatchedName = parsed.trips[0].customerMatchedName;
                }
            } catch (_lookupErr) {
                console.warn('CRM-Lookup-Fehler:', _lookupErr.message);
            }

            // ًں†• v6.62.150: Stop-Timeline â€” alle Adressen geocodieren, OSRM-Route mit
            // Waypoints rechnen, daraus Etappen-Zeiten + arrivalTime pro Stopp ableiten.
            // Wartezeit pro Zwischenstopp aus settings/waypointDwellMin (Default 3 Min).
            try {
                const dwellSnap = await db.ref('settings/waypointDwellMin').once('value');
                const dwellMin = Math.max(0, Number(dwellSnap.val()) || 3);
                if (parsed.trips && Array.isArray(parsed.trips)) {
                    for (const t of parsed.trips) {
                        try {
                            if (!t.pickup || !t.destination) continue;
                            const pickC = await geocode(t.pickup);
                            const destC = await geocode(t.destination);
                            if (!pickC || !destC) continue;
                            t.pickupLat = pickC.lat; t.pickupLon = pickC.lon;
                            t.destinationLat = destC.lat; t.destinationLon = destC.lon;
                            // ًں›،ï¸ڈ v6.62.192: Patrick (01.05.): "warum ist die Fahrt vom 25.04
                            // nach Koserow nicht importiert?". Befund: Waypoint-Geocode-Fail
                            // hat den Stop aus wpCoords gekickt, Timeline-Schleife unten nutzte
                            // aber weiter t.waypoints[i] als Index â†’ Adressen verschoben +
                            // ein Stop verschwand komplett. aja Strandhotel Bansin (Hأ¶hne+
                            // Reichert-Drop) war weg, sie wأ¤ren mit nach Koserow gefahren.
                            // Fix: existing-coords nutzen wenn vorhanden (kein redundanter
                            // Geocode-Call), validWaypoints tracken, und t.waypoints am
                            // Ende auf valide Liste reduzieren damit Indices matchen.
                            const wpCoords = [];
                            const validWaypoints = [];
                            if (Array.isArray(t.waypoints)) {
                                for (let i = 0; i < t.waypoints.length; i++) {
                                    const wp = t.waypoints[i];
                                    const addr = (wp && (wp.address || wp.addr)) || (typeof wp === 'string' ? wp : null);
                                    if (!addr) continue;
                                    let c;
                                    if (typeof wp === 'object' && wp.lat && wp.lon) {
                                        c = { lat: wp.lat, lon: wp.lon };
                                    } else {
                                        c = await geocode(addr);
                                    }
                                    if (c && c.lat && c.lon) {
                                        wpCoords.push({ lat: c.lat, lon: c.lon });
                                        const enriched = (typeof wp === 'object')
                                            ? Object.assign({}, wp, { lat: c.lat, lon: c.lon })
                                            : { address: addr, lat: c.lat, lon: c.lon };
                                        validWaypoints.push(enriched);
                                        t.waypoints[i] = enriched;
                                    } else {
                                        console.warn('Geocode-Fail Waypoint:', addr, 'â€” Trip', t.pickup, 'â†’', t.destination, 'â€” Stop wird aus Timeline entfernt damit Indices matchen.');
                                    }
                                }
                                // Wenn Stops gedroppt wurden: t.waypoints auf validierte Liste
                                // reduzieren, sonst ueberlappt die Timeline-Schleife unten falsch.
                                if (validWaypoints.length !== t.waypoints.length) {
                                    t.waypoints = validWaypoints;
                                }
                            }
                            const route = await calculateRoute(
                                { lat: pickC.lat, lon: pickC.lon },
                                { lat: destC.lat, lon: destC.lon },
                                wpCoords
                            );
                            if (!route) continue;
                            t.distance = route.distance;
                            t.duration = route.duration;
                            t.legs = route.legs || [];
                            t.dwellMin = dwellMin;
                            // Stop-Timeline aufbauen â€” Pickup + N Waypoints + Destination
                            const baseTs = t.datetime ? Date.parse(t.datetime) : null;
                            if (baseTs && !isNaN(baseTs) && route.legs && route.legs.length > 0) {
                                let cursor = baseTs;
                                const timeline = [{ kind: 'pickup', address: t.pickup, name: t.pickupName || null, arrivalTime: cursor }];
                                let totalDwell = 0;
                                for (let i = 0; i < route.legs.length; i++) {
                                    cursor += route.legs[i].duration * 60000;
                                    const isLast = (i === route.legs.length - 1);
                                    if (isLast) {
                                        timeline.push({ kind: 'destination', address: t.destination, name: t.destinationName || null, arrivalTime: cursor });
                                    } else {
                                        const wp = (t.waypoints || [])[i];
                                        timeline.push({
                                            kind: 'waypoint',
                                            address: (wp && (wp.address || wp.addr)) || (typeof wp === 'string' ? wp : null),
                                            name: (wp && wp.name) || null,
                                            arrivalTime: cursor,
                                            dwellMin
                                        });
                                        cursor += dwellMin * 60000;
                                        totalDwell += dwellMin;
                                    }
                                }
                                t.timeline = timeline;
                                t.totalDwellMin = totalDwell;
                                t.destinationArrivalTime = cursor;
                            }
                        } catch (_tripErr) {
                            console.warn('Trip-Timeline-Fehler:', _tripErr.message);
                        }
                    }
                    // Top-Level Spiegelung fuer Backwards-compat (erste Fahrt)
                    if (parsed.trips[0]) {
                        if (parsed.trips[0].timeline) parsed.timeline = parsed.trips[0].timeline;
                        if (parsed.trips[0].legs) parsed.legs = parsed.trips[0].legs;
                        if (parsed.trips[0].dwellMin != null) parsed.dwellMin = parsed.trips[0].dwellMin;
                    }
                }
            } catch (_timelineErr) {
                console.warn('Timeline-Fehler:', _timelineErr.message);
            }

            // Audit-Log
            // v6.62.228: Patrick (03.05. 19:40): "kann ich zu dem importierten Auftrag
            // springen?". Push-Key zurueckgeben damit der Browser ihn in jede ride als
            // auftragImportId speichert â€” dann kann das edit-Modal zurueck springen.
            let _importLogId = null;
            try {
                const _logRef = await db.ref('importLog').push({
                    t: Date.now(),
                    filename: filename || 'unbekannt',
                    mediaType: _media,
                    parsed,
                    success: true
                });
                _importLogId = _logRef.key;
            } catch (_logErr) { /* still */ }
            res.status(200).json({ ok: true, parsed, importLogId: _importLogId });
        } catch (err) {
            console.error('importAuftragPdf Fehler:', err.message, err.stack);
            res.status(500).json({ error: err.message });
        }
    }
);

