// v6.62.258: DMS-Wiedervorlage â€” schickt Telegram-Push wenn reminderAt
// fأ¤llig wird. Plus auto-Reminder 5 Tage vor dueDate fأ¼r unbezahlte
// Rechnungen. Lأ¤uft jede Stunde.
// â•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گ
exports.scheduledReminderCheck = onSchedule(
    {
        schedule: 'every 60 minutes',
        region: 'europe-west1',
        timeoutSeconds: 60,
        memory: '256MiB'
    },
    async (event) => {
        try {
            const now = Date.now();
            const docsSnap = await db.ref('docs').once('value');
            const docs = docsSnap.val() || {};
            const dueReminders = [];
            const dueDateAlerts = [];

            for (const [docId, d] of Object.entries(docs)) {
                if (!d) continue;
                // 1. Manuelle Reminders
                if (d.reminderAt && !d.reminderSent && d.reminderAt <= now) {
                    dueReminders.push({ docId, ...d });
                }
                // 2. Auto-Reminder 5 Tage vor Faelligkeit (nur unbezahlte Rechnungen)
                if (d.dueDate && !d.dueDateAlertSent && (d.workflowStatus !== 'bezahlt' && d.workflowStatus !== 'erledigt')) {
                    const due = new Date(d.dueDate + 'T09:00:00').getTime();
                    const fiveDaysBefore = due - 5 * 86400000;
                    if (now >= fiveDaysBefore && now < due + 86400000) {
                        dueDateAlerts.push({ docId, ...d, _due: due });
                    }
                }
            }

            console.log(`ًں“… ReminderCheck: ${dueReminders.length} manuelle + ${dueDateAlerts.length} Faelligkeit-Alerts`);

            for (const r of dueReminders) {
                const wIcon = r.wichtigkeit === 'hoch' ? 'ًں”´' : r.wichtigkeit === 'mittel' ? 'ًںں،' : 'ًںں¢';
                let msg = `âڈ° <b>Wiedervorlage</b> ${wIcon}\n\n`;
                msg += `ًں“„ <b>${r.lieferant || '?'}</b>${r.dokumenttyp ? ' â€” ' + r.dokumenttyp : ''}\n`;
                if (r.datum) msg += `ًں“… ${r.datum}`;
                if (r.betrag) msg += ` آ· ًں’¶ ${r.betrag.toFixed(2).replace('.', ',')} â‚¬`;
                msg += '\n';
                if (r.reminderNote) msg += `\nًں“‌ <b>Notiz:</b> ${r.reminderNote}\n`;
                if (r.summary) msg += `\n${r.summary}\n`;
                if (r.aktionsEmpfehlung) msg += `\nًں“‹ <b>KI-Empfehlung:</b> ${r.aktionsEmpfehlung}\n`;
                if (r.storageUrl) msg += `\nًں”— <a href="${r.storageUrl}">Original ansehen</a>`;
                try {
                    await db.ref('claudeBridge/outbox/' + Date.now() + '_rem_' + r.docId).set({
                        message: msg, targetChatId: 6229490043, via: 'claude', ts: Date.now(),
                        source: 'reminder', docId: r.docId, parseMode: 'HTML'
                    });
                    await db.ref('docs/' + r.docId + '/reminderSent').set(Date.now());
                    console.log(`âœ… Reminder gesendet: ${r.docId}`);
                } catch (e) {
                    console.error(`â‌Œ Reminder ${r.docId} failed:`, e.message);
                }
            }

            for (const a of dueDateAlerts) {
                const daysLeft = Math.round((a._due - now) / 86400000);
                let msg = `âڑ ï¸ڈ <b>Fأ¤lligkeit-Alarm</b> ًں”´\n\n`;
                msg += `ًں“„ <b>${a.lieferant || '?'}</b>${a.dokumenttyp ? ' â€” ' + a.dokumenttyp : ''}\n`;
                msg += `ًں“… Fأ¤llig in <b>${daysLeft >= 0 ? daysLeft + ' Tag(en)' : 'BEREITS أœBERFأ„LLIG'}</b> (${a.dueDate})\n`;
                if (a.betrag) msg += `ًں’¶ Betrag: ${a.betrag.toFixed(2).replace('.', ',')} â‚¬\n`;
                if (a.lieferantEmail) msg += `ًں“§ Email: ${a.lieferantEmail}\n`;
                if (a.aktionsEmpfehlung) msg += `\nًں“‹ <b>KI-Empfehlung:</b> ${a.aktionsEmpfehlung}\n`;
                if (a.storageUrl) msg += `\nًں”— <a href="${a.storageUrl}">Original</a>`;
                try {
                    await db.ref('claudeBridge/outbox/' + Date.now() + '_due_' + a.docId).set({
                        message: msg, targetChatId: 6229490043, via: 'claude', ts: Date.now(),
                        source: 'due-alert', docId: a.docId, parseMode: 'HTML'
                    });
                    await db.ref('docs/' + a.docId + '/dueDateAlertSent').set(Date.now());
                    console.log(`âœ… DueDate-Alert gesendet: ${a.docId}`);
                } catch (e) {
                    console.error(`â‌Œ DueDate-Alert ${a.docId} failed:`, e.message);
                }
            }
        } catch (e) {
            console.error('scheduledReminderCheck error:', e);
        }
    }
);

