// ًں†• v6.62.10: NOTFALL-RIDE-FIX â€” Patrick stuck mit Fahrt, Handy schreibt nicht.
// Aufruf: curl -X POST "URL?key=SECRET" -d '{"rideId":"X","status":"completed"}'
// Setzt Status + acceptedAt/onWayAt/arrivedAt/pickedUpAt Timestamps + admin-bypass Lock.
// â•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گ
exports.claudeFixRide = onRequest(
    { region: 'europe-west1', invoker: 'public' },
    async (req, res) => {
        res.set('Access-Control-Allow-Origin', '*');
        if (req.method === 'OPTIONS') { res.status(204).send(''); return; }
        const key = req.query.key;
        const keySnap = await db.ref('settings/healthCheckKey').once('value');
        const validKey = keySnap.val() || 'funk-taxi-heringsdorf-2026';
        if (!key || key !== validKey) { res.status(403).json({ error: 'Forbidden' }); return; }
        try {
            const body = (typeof req.body === 'object') ? req.body : JSON.parse(req.body || '{}');
            const rideId = body.rideId;
            const newStatus = body.status;
            if (!rideId || !newStatus) { res.status(400).json({ error: 'rideId+status required' }); return; }
            const now = Date.now();
            const upd = {
                status: newStatus,
                updatedAt: now,
                fixedBy: 'claudeFixRide-v6.62.10',
                fixedAt: now,
                fixReason: body.reason || 'Manueller Notfall-Fix'
            };
            // Timeline-Felder rأ¼ckwirkend setzen fأ¼r vollstأ¤ndige Logs
            if (newStatus === 'completed') {
                if (!body.skipTimeline) {
                    upd.onWayAt = upd.onWayAt || now - 600000;
                    upd.arrivedAt = upd.arrivedAt || now - 120000;
                    upd.pickedUpAt = upd.pickedUpAt || now - 60000;
                    upd.completedAt = now;
                }
            } else if (newStatus === 'on_way') upd.onWayAt = now;
            else if (newStatus === 'arrived') upd.arrivedAt = now;
            else if (newStatus === 'picked_up') upd.pickedUpAt = now;
            else if (newStatus === 'cancelled' || newStatus === 'storniert') {
                upd.cancelledAt = now;
                upd.cancelledBy = body.cancelledBy || 'claude-emergency-fix';
            }
            // ًں”§ v6.62.63: Wenn auf 'vorbestellt' zurueckgesetzt, MUSS acceptedAt/assignedAt/assignmentLocked
            // entfernt werden, sonst skipt PUSH-REMINDER (functions/index.js:17750) die Ride am Pickup-Tag
            // weil 'r.acceptedAt' truthy ist â†’ kein zweiter FCM-Push. Birgit-Lenzkes-Bug 28.04.
            if (newStatus === 'vorbestellt') {
                upd.acceptedAt = null;
                upd.assignedAt = null;
                upd.assignmentLocked = null;
                upd.statusTransitionedAt = now;
                upd.statusTransitionReason = upd.fixReason + ' (acceptedAt/assignedAt geloescht damit PUSH-REMINDER greift)';
            }
            await db.ref('rides/' + rideId).update(upd);
            await addRideLog(rideId, 'ًںڑ‘', `NOTFALL-FIX: status â†’ ${newStatus}`, {
                quelle: 'claudeFixRide v6.62.10',
                grund: upd.fixReason
            });
            res.json({ ok: true, rideId, newStatus, updates: upd });
        } catch (err) {
            console.error('claudeFixRide error:', err);
            res.status(500).json({ error: err.message });
        }
    }
);

// â•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گ
// HEALTH CHECK â€” Live-Status fأ¼r Terminal-Diagnose
// Aufruf: node check.js  ODER  curl "URL?key=SECRET"
// â•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گ
exports.healthCheck = onRequest(
    { region: 'europe-west1', invoker: 'public' },
    async (req, res) => {
        res.set('Access-Control-Allow-Origin', '*');
        if (req.method === 'OPTIONS') { res.status(204).send(''); return; }

        // Key-Check: statischer Health-Check Key (in Firebase settings/healthCheckKey speicherbar)
        const key = req.query.key;
        // Primأ¤r: Firebase Datenbank Key; Fallback: statischer Key
        const keySnap = await db.ref('settings/healthCheckKey').once('value');
        const savedKey = keySnap.val();
        const STATIC_KEY = 'funk-taxi-heringsdorf-2026';
        const validKey = savedKey || STATIC_KEY;
        if (!key || key !== validKey) {
            res.status(403).json({ error: 'Kein Zugriff. ?key= Parameter fehlt. Standard: funk-taxi-heringsdorf-2026' });
            return;
        }

        try {
            const now = Date.now();
            const berlinNow = new Date(new Date().toLocaleString('en-US', { timeZone: 'Europe/Berlin' }));

            // 1. Fahrzeuge
            const vehiclesSnap = await db.ref('vehicles').once('value');
            const vehicles = vehiclesSnap.val() || {};
            const vehicleStatus = {};
            let onlineCount = 0;
            for (const [id, v] of Object.entries(vehicles)) {
                const isOnline = v.online === true;
                const gpsAge = v.lastUpdate ? Math.round((now - v.lastUpdate) / 60000) : null;
                if (isOnline) onlineCount++;
                vehicleStatus[id] = {
                    name: v.name || id,
                    online: isOnline,
                    gpsAgeMin: gpsAge,
                    gpsStale: gpsAge !== null && gpsAge > 30,
                };
            }

            // 2. Aktive Fahrten
            const ridesSnap = await db.ref('rides').orderByChild('pickupTimestamp')
                .startAt(now - 2 * 3600000).endAt(now + 24 * 3600000).once('value');
            const activeStatuses = ['new', 'assigned', 'vorbestellt', 'accepted', 'picked_up', 'on_way'];
            const rides = { new: [], assigned: [], vorbestellt: [], accepted: [], running: [] };
            ridesSnap.forEach(child => {
                const r = child.val();
                if (r.status === 'new') rides.new.push({ id: child.key, name: r.customerName, pickup: r.pickup });
                else if (r.status === 'assigned') rides.assigned.push({ id: child.key, name: r.customerName });
                else if (r.status === 'vorbestellt') rides.vorbestellt.push({ id: child.key, name: r.customerName, time: r.pickupTime });
                else if (r.status === 'accepted') rides.accepted.push({ id: child.key, name: r.customerName });
                else if (['picked_up', 'on_way'].includes(r.status)) rides.running.push({ id: child.key, name: r.customerName, status: r.status });
            });

            // 3. Telegram Bot
            const webhookActiveSnap = await db.ref('settings/telegram/webhookActive').once('value');
            const pendingSnap = await db.ref('settings/telegram/pending').once('value');
            const pendingCount = Object.keys(pendingSnap.val() || {}).length;

            // 4. Buchungssystem Online?
            const bookingOnlineSnap = await db.ref('settings/bookingSystemOnline').once('value');

            // 5. Schichtplan heute
            const dateStr = berlinNow.toISOString().slice(0, 10);
            const shiftsSnap = await db.ref('vehicleShifts').once('value');
            const shifts = shiftsSnap.val() || {};
            const inShiftToday = [];
            const CAPACITY = { 'pw-ik-222': 4, 'pw-my-222-e': 4, 'pw-ki-222': 4, 'pw-sk-222': 8, 'vg-lk-111': 8, 'pw-ym-222-e': 4 };
            for (const [vid, vShifts] of Object.entries(shifts)) {
                const dayEntry = vShifts[dateStr];
                if (dayEntry && dayEntry.active !== false) inShiftToday.push(vid);
            }

            const status = {
                timestamp: new Date().toISOString(),
                version: CLOUD_FUNCTIONS_VERSION,
                ok: true,
                vehicles: { online: onlineCount, total: Object.keys(vehicles).length, details: vehicleStatus },
                rides: {
                    new: rides.new.length,
                    assigned: rides.assigned.length,
                    vorbestellt: rides.vorbestellt.length,
                    accepted: rides.accepted.length,
                    running: rides.running.length,
                    details: rides
                },
                telegram: {
                    webhookActive: webhookActiveSnap.val(),
                    pendingConversations: pendingCount,
                },
                bookingSystemOnline: bookingOnlineSnap.val(),
                shiftToday: { vehiclesPlanned: inShiftToday.length, vehicleIds: inShiftToday },
                warnings: []
            };

            // Warnungen generieren
            if (onlineCount === 0) status.warnings.push('âڑ ï¸ڈ Kein Fahrzeug online!');
            if (rides.new.length > 0) status.warnings.push(`ًں†• ${rides.new.length} unbearbeitete Sofortfahrt(en)!`);
            for (const [id, v] of Object.entries(vehicleStatus)) {
                if (v.online && v.gpsStale) status.warnings.push(`ًں“چ ${v.name}: GPS veraltet (${v.gpsAgeMin} Min)`);
            }
            if (!webhookActiveSnap.val()) status.warnings.push('âڑ ï¸ڈ Telegram Webhook NICHT aktiv!');
            if (bookingOnlineSnap.val() === false) status.warnings.push('ًں”´ Buchungssystem ist OFFLINE!');

            if (status.warnings.length === 0) status.warnings.push('âœ… Alles OK');
            status.ok = !status.warnings.some(w => w.startsWith('âڑ ï¸ڈ') || w.startsWith('ًں†•'));

            res.status(200).json(status);
        } catch (e) {
            res.status(500).json({ error: e.message, ok: false });
        }
    }
);

// â•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گ
// ًں†• v6.38.96: SMS-QUEUE â€” Sendet Telegram-Nachricht an Admin
// Macrodroid fأ¤ngt Telegram-Notification ab â†’ sendet SMS أ¼ber SIM
// Format: ًں“²SMS|+49151...|SMS Text hier
// â•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گ
exports.onSmsQueued = onValueCreated(
    {
        ref: '/smsQueue/{smsId}',
        region: 'europe-west1',
        instance: 'taxi-heringsdorf-default-rtdb'
    },
    async (event) => {
        const smsId = event.params.smsId;
        const smsData = event.data.val();
        if (!smsData || !smsData.phone || !smsData.text) return;
        if (smsData.status !== 'pending') return;

        console.log(`ًں“² onSmsQueued: ${smsId} â€” ${smsData.phone} â€” ${smsData.type}`);

        try {
            // v6.62.49: Native-SMS-Gateway statt Macrodroid-Telegram-Trigger.
            // settings/sms/gatewayVehicleId zeigt auf das Fahrzeug-Handy mit aktiver
            // Funk-Taxi-App + SEND_SMS-Permission. Default: pw-ym-222-e (Patrick's Tesla).
            // v6.62.94: Typo gefixt â€” war 'pw-my-222-e' (m statt y), das Vehicle gibt's
            // gar nicht. Wenn das Setting fehlte, fiel der Fallback ins Leere und SMS
            // landeten still im Macrodroid-Pfad. Korrekt: pw-ym-222-e.
            const gwSnap = await db.ref('settings/sms/gatewayVehicleId').once('value');
            const gatewayVid = gwSnap.val() || 'pw-ym-222-e';

            const fcmOk = await sendFCMToVehicle(gatewayVid, {
                type: 'send_sms',
                smsId,
                phone: smsData.phone,
                text: smsData.text
            });

            if (fcmOk) {
                await db.ref(`smsQueue/${smsId}`).update({
                    status: 'fcm_sent',
                    sentAt: Date.now(),
                    gatewayVehicle: gatewayVid
                });
                console.log(`âœ… SMS-FCM an Gateway ${gatewayVid} gesendet: ${smsData.phone}`);
                // Native quittiert mit status='sent' oder 'failed' wenn die SMS verarbeitet wurde
            } else {
                // Fallback: Macrodroid-Telegram-Trigger (alter Pfad) falls kein FCM-Token
                let smsChatId = null;
                const smsChatSnap = await db.ref('settings/sms/telegramChatId').once('value');
                smsChatId = smsChatSnap.val();
                if (!smsChatId) {
                    const adminSnap = await db.ref('settings/telegram/adminChats').once('value');
                    const admins = adminSnap.val();
                    if (Array.isArray(admins) && admins.length > 0) smsChatId = admins[0];
                    else if (typeof admins === 'object' && admins) smsChatId = Object.values(admins)[0];
                    else if (admins) smsChatId = admins;
                }
                if (!smsChatId) {
                    await db.ref(`smsQueue/${smsId}`).update({ status: 'failed', error: 'Kein FCM-Token + kein Chat-ID', processedAt: Date.now() });
                    return;
                }
                await sendTelegramMessage(smsChatId, `ًں“²SMSNUM ${smsData.phone}`, { parse_mode: undefined });
                await new Promise(r => setTimeout(r, 1000));
                await sendTelegramMessage(smsChatId, `ًں“²SMSTXT ${smsData.text}`, { parse_mode: undefined });
                await db.ref(`smsQueue/${smsId}`).update({
                    status: 'telegram_sent_fallback',
                    sentAt: Date.now(),
                    sentTo: smsChatId
                });
            }

        } catch (err) {
            console.error('â‌Œ onSmsQueued Fehler:', err.message);
            await db.ref(`smsQueue/${smsId}`).update({ status: 'failed', error: err.message, processedAt: Date.now() });
        }
    }
);

// â•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گ
// ًں†• v6.38.96: ANFRAGEN-TRIGGER â€” Telegram bei neuer Web-Anfrage
// â•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گâ•گ
